import React, { useState, useEffect, useRef } from 'react';
import { Link } from 'react-router-dom';
import { API_SEARCH, POSTER_PATH, WIDTH_500, avg } from '../constant';
import { AiFillStar } from "react-icons/ai";
import { LazyLoadImage } from 'react-lazy-load-image-component';
import axios from 'axios';

const Navigation = () => {

  const [searchTerm, setSearchTerm] = useState([]);
  const [searchResults, setSearchResults] = useState([]);
  const [data, setData] = useState([]);
  const wrapperRef = useRef(null)

  const handleChange = event => {
    setSearchTerm(event.target.value);
    if (event.target.value) {
      if (document.getElementById('search').classList.contains('hide')) {
        document.getElementById('search').classList.remove('hide');
      }
      const getData = async () => {
        axios.get(API_SEARCH + event.target.value)
          .then((data) => {
            setData(data.data.results);
          })
          .catch((error) => {
            console.error(error);
          })
      }

      getData();
    }
    else {
      setData([]);
      if (!document.getElementById('search').classList.contains('hide')) {
        document.getElementById('search').classList.add('hide');
      }
    }
  };

  document.body.addEventListener('click', (event) => {
    if (!document.getElementById('search').classList.contains('hide')) {
      document.getElementById('search').classList.add('hide');
    }
    if (wrapperRef.current && !wrapperRef.current.contains(event.target)) {
      if (document.getElementById('navbarSupportedContent').classList.contains('open')) {
        document.getElementById('navbarSupportedContent').classList.remove('show');
        document.getElementById('navbarSupportedContent').classList.remove('open');
        document.getElementById('navbarToggler').classList.remove('open');
      }
    }
  });

  const handleNav = (e) => {
    e.preventDefault();
    if (document.getElementById('navbarSupportedContent').classList.contains('open')) {
      document.getElementById('navbarSupportedContent').classList.remove('show');
      document.getElementById('navbarSupportedContent').classList.remove('open');
      document.getElementById('navbarToggler').classList.remove('open');
    }
    else {
      document.getElementById('navbarSupportedContent').classList.add('show');
      document.getElementById('navbarSupportedContent').classList.add('open');
      document.getElementById('navbarToggler').classList.add('open');
    }
  };

  const handleClick = () => {
    if (!document.getElementById('search').classList.contains('hide')) {
      document.getElementById('search').classList.add('hide');
    }
    if (document.getElementById('navbarSupportedContent').classList.contains('open')) {
      document.getElementById('navbarSupportedContent').classList.remove('show');
      document.getElementById('navbarSupportedContent').classList.remove('open');
      document.getElementById('navbarToggler').classList.remove('open');
    }
  }

  useEffect(() => {
    const results = data.length>0 ? data.map((dataRow, index) => (
      <Link key={index} to={dataRow.media_type ? dataRow.media_type === 'movie' ? '/movieshub/movie/' + dataRow.id : dataRow.media_type === 'tv' ? '/movieshub/tv/' + dataRow.id : '/movieshub/person/' + dataRow.id : '/movieshub/movie/' + dataRow.id} onClick={handleClick}>
        <div className="row mt-3">
          <div className="col-3">
            <LazyLoadImage className="img-search" src={dataRow.poster_path ? POSTER_PATH + WIDTH_500 + dataRow.poster_path : POSTER_PATH + WIDTH_500 + dataRow.profile_path} effect="opacity" alt={dataRow.title ? dataRow.title : dataRow.name} onError={(e) => { e.target.onerror = null; e.target.src = "https://fakeimg.pl/200x300?text=MoviesHub&font=bebas&font_size=25" }} />
          </div>
          <div className="col ms-2">
            <div>{dataRow.name ? dataRow.name : dataRow.title}</div>
            <div className="text-muted">{dataRow.gender ? dataRow.gender === 1 ? 'Female' : 'Male' : dataRow.release_date || dataRow.first_air_date ? (`${dataRow.release_date}`).substring(0, 4) !== 'unde' ? (`${dataRow.release_date}`).substring(0, 4) : (`${dataRow.first_air_date}}`).substring(0, 4) : ''}</div>
            <div>{dataRow.vote_average ? <><AiFillStar /> {avg(dataRow.vote_average)}</> : ''}</div>
            <div>
              {dataRow['known_for'] ? dataRow['known_for'].map((dataKnown, index) => (
                <span className="genre" key={index}>{dataKnown.title ? dataKnown.title : dataKnown.name}</span>
              )) : ''}
            </div>
          </div>
        </div>
      </Link>
    )) : 'No results available...';
    setSearchResults(results);
  }, [data, searchTerm]);

  return (
    <nav className="navbar navbar-expand-md navbar-dark bg-grey-dark" ref={wrapperRef}>
      <div className="container mt-1 mb-1">
        <Link className="navbar-brand" to='/movieshub/'>Movies<span className="text-primary" onClick={handleClick}>Hub</span></Link>
        <button className="navbarToggler" type="button" onClick={handleNav}  aria-label="MENU">
          <div id="navbarToggler">
            <span></span>
            <span></span>
          </div>
        </button>
        <div className="collapse navbar-collapse" id="navbarSupportedContent">
          <ul className="navbar-nav ms-auto mt-3 mt-md-0">
            <li className="nav-item ms-md-5">
              <Link className="nav-link" to='/movieshub/movie' onClick={handleClick}>Movies</Link>
            </li>
            <li className="nav-item ms-md-5">
              <Link className="nav-link" to='/movieshub/tv' onClick={handleClick}>TV</Link>
            </li>
            <li className="nav-item ms-md-5">
              <Link className="nav-link" to='/movieshub/people' onClick={handleClick}>People</Link>
            </li>
            <li className="nav-item ms-md-5 mt-3 mt-md-0">
              <input
                className="form-control"
                type="text"
                placeholder="Search Movies, TV ..."
                value={searchTerm}
                onChange={handleChange}
              />
              <div className="position-relative hide" id="search">
                <div className="position-absolute search-results search-height">
                  {searchResults}
                </div>
              </div>
            </li>
          </ul>
        </div>
      </div>
    </nav>
  )
}

export default Navigation